import React, { useState } from "react";
import {
  StyleSheet,
  SafeAreaView,
  FlatList,
  Text,
  View,
  Pressable,
} from "react-native";

import EventCard from "./components/EventCard";
import { EVENTS } from "./data/events";

export default function App() {
  const [eventsList, setEventsList] = useState(EVENTS);
  const [showFavoritesOnly, setShowFavoritesOnly] = useState(false);

  const toggleFavorite = (id) => {
    setEventsList(
      eventsList.map((event) =>
        event.id === id ? { ...event, favorite: !event.favorite } : event
      )
    );
  };

  const displayedEvents = showFavoritesOnly
    ? eventsList.filter((event) => event.favorite)
    : eventsList;

  return (
    <SafeAreaView style={styles.container}>
      <View style={styles.headerContainer}>
        <Text style={styles.header}>Lista Wydarzeń</Text>

        <Pressable
          style={[
            styles.filterButton,
            showFavoritesOnly && styles.filterButtonActive,
          ]}
          onPress={() => setShowFavoritesOnly(!showFavoritesOnly)}
        >
          <Text
            style={[
              styles.filterText,
              showFavoritesOnly && styles.filterTextActive,
            ]}
          >
            {showFavoritesOnly
              ? "⭐ Pokaż wszystkie"
              : "🤍 Pokaż tylko ulubione"}
          </Text>
        </Pressable>
      </View>

      <FlatList
        data={displayedEvents}
        keyExtractor={(item) => item.id}
        renderItem={({ item }) => (
          <EventCard
            title={item.title}
            date={item.date}
            location={item.location}
            category={item.category}
            favorite={item.favorite}
            onToggle={() => toggleFavorite(item.id)}
          />
        )}
        ListEmptyComponent={
          <Text style={styles.emptyMessage}>
            Nie masz jeszcze ulubionych wydarzeń.
          </Text>
        }
      />
    </SafeAreaView>
  );
}

const styles = StyleSheet.create({
  container: {
    flex: 1,
    backgroundColor: "#ecf0f1",
    paddingHorizontal: 16,
    paddingTop: 40,
  },
  headerContainer: {
    marginBottom: 20,
    alignItems: "center",
  },
  header: {
    fontSize: 28,
    fontWeight: "bold",
    color: "#333",
    marginBottom: 10,
  },
  filterButton: {
    paddingVertical: 8,
    paddingHorizontal: 16,
    backgroundColor: "#e0e0e0",
    borderRadius: 20,
  },
  filterButtonActive: {
    backgroundColor: "#ffd700",
  },
  filterText: {
    fontWeight: "bold",
    color: "#555",
  },
  filterTextActive: {
    color: "#000",
  },
  emptyMessage: {
    textAlign: "center",
    marginTop: 20,
    fontSize: 16,
    color: "gray",
    fontStyle: "italic",
  },
});
